def sat_brute_force(formula, n_vars):
    # Try all 2^n assignments
    for assignment in range(2 ** n_vars):
        bits = format(assignment, f'0{n_vars}b')
        values = [bool(int(bits[i])) for i in range(n_vars)]
        if evaluate_formula(formula, values):
            return True, values
    return False, None

def evaluate_formula(formula, values):
    # Evaluate each clause (OR of literals)
    for clause in formula:
        clause_true = False
        for literal in clause:
            var = abs(literal) - 1
            is_true = values[var] if literal > 0 else not values[var]
            if is_true:
                clause_true = True
                break
        if not clause_true:
            return False
    return True

# Time Complexity: O(2^n × m × k) where n=vars, m=clauses, k=clause length

