#include <stdio.h>
#include <stdlib.h>

int knapsack(int W, int n, int wt[], int val[]) {
    // dp[w] = max value achievable with weight limit w
    int *dp = (int*)calloc(W + 1, sizeof(int));

    for (int i = 0; i < n; i++) {
        for (int w = W; w >= wt[i]; w--) {
            dp[w] = max(dp[w], dp[w - wt[i]] + val[i]);
        }
    }

    int result = dp[W];
    free(dp);
    return result;
}

// Time Complexity: O(n * W)
// Space Complexity: O(W)
// This is pseudopolynomial because it depends on W (weight value),
// not just n (number of items). If W is large (e.g., 2^30), 
// this becomes impractical even though W is a single number.

int max(int a, int b) {
    return (a > b) ? a : b;
}

int main() {
    int val[] = {60, 100, 120};
    int wt[] = {10, 20, 30};
